CREATE TYPE "LeaseStatus" AS ENUM ('DRAFT', 'ACTIVE', 'NOTICE_TERMINATED', 'EXPIRED', 'ARCHIVED');
CREATE TYPE "LeasePartyRole" AS ENUM ('TENANT', 'GUARANTOR', 'CO_TENANT');
CREATE TYPE "LeaseDocumentType" AS ENUM ('AGREEMENT', 'ADDENDUM', 'IDENTITY_PROOF', 'OTHER');
CREATE TABLE "Lease" ("id" TEXT NOT NULL, "organizationId" TEXT NOT NULL, "unitId" TEXT NOT NULL, "code" TEXT NOT NULL, "status" "LeaseStatus" NOT NULL DEFAULT 'DRAFT', "startsAt" TIMESTAMP(3) NOT NULL, "endsAt" TIMESTAMP(3) NOT NULL, "terminatedAt" TIMESTAMP(3), "terminationReason" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3), CONSTRAINT "Lease_pkey" PRIMARY KEY ("id"), CONSTRAINT "Lease_dates_check" CHECK ("endsAt" > "startsAt"));
CREATE TABLE "LeaseTerms" ("id" TEXT NOT NULL, "leaseId" TEXT NOT NULL, "rentAmount" DECIMAL(14,2) NOT NULL, "securityDeposit" DECIMAL(14,2) NOT NULL DEFAULT 0, "escalationRate" DECIMAL(5,2), "escalationMonths" INTEGER, "gracePeriodDays" INTEGER NOT NULL DEFAULT 0, "noticePeriodDays" INTEGER NOT NULL DEFAULT 30, "lateFeeAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "currency" TEXT NOT NULL DEFAULT 'INR', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseTerms_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseTerms_nonnegative_check" CHECK ("rentAmount" >= 0 AND "securityDeposit" >= 0 AND "lateFeeAmount" >= 0 AND "gracePeriodDays" >= 0 AND "noticePeriodDays" >= 0));
CREATE TABLE "LeaseParty" ("id" TEXT NOT NULL, "leaseId" TEXT NOT NULL, "role" "LeasePartyRole" NOT NULL, "name" TEXT NOT NULL, "email" TEXT, "mobile" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseParty_pkey" PRIMARY KEY ("id"));
CREATE TABLE "LeaseDocument" ("id" TEXT NOT NULL, "leaseId" TEXT NOT NULL, "type" "LeaseDocumentType" NOT NULL DEFAULT 'OTHER', "name" TEXT NOT NULL, "storageKey" TEXT NOT NULL, "mimeType" TEXT NOT NULL, "sizeBytes" INTEGER NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3), CONSTRAINT "LeaseDocument_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseDocument_size_check" CHECK ("sizeBytes" >= 0));
CREATE TABLE "LeaseRenewal" ("id" TEXT NOT NULL, "leaseId" TEXT NOT NULL, "previousEndsAt" TIMESTAMP(3) NOT NULL, "renewedEndsAt" TIMESTAMP(3) NOT NULL, "rentAmount" DECIMAL(14,2), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "LeaseRenewal_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseRenewal_dates_check" CHECK ("renewedEndsAt" > "previousEndsAt"));
CREATE UNIQUE INDEX "Lease_organizationId_code_key" ON "Lease"("organizationId", "code"); CREATE INDEX "Lease_organizationId_status_deletedAt_idx" ON "Lease"("organizationId", "status", "deletedAt"); CREATE INDEX "Lease_unitId_status_startsAt_endsAt_idx" ON "Lease"("unitId", "status", "startsAt", "endsAt"); CREATE UNIQUE INDEX "Lease_one_active_per_unit_key" ON "Lease"("unitId") WHERE "deletedAt" IS NULL AND "status" IN ('ACTIVE', 'NOTICE_TERMINATED'); CREATE UNIQUE INDEX "LeaseTerms_leaseId_key" ON "LeaseTerms"("leaseId"); CREATE INDEX "LeaseParty_leaseId_role_idx" ON "LeaseParty"("leaseId", "role"); CREATE UNIQUE INDEX "LeaseDocument_leaseId_storageKey_key" ON "LeaseDocument"("leaseId", "storageKey"); CREATE INDEX "LeaseDocument_leaseId_type_deletedAt_idx" ON "LeaseDocument"("leaseId", "type", "deletedAt"); CREATE INDEX "LeaseRenewal_leaseId_renewedEndsAt_idx" ON "LeaseRenewal"("leaseId", "renewedEndsAt");
ALTER TABLE "Lease" ADD CONSTRAINT "Lease_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Lease" ADD CONSTRAINT "Lease_unitId_fkey" FOREIGN KEY ("unitId") REFERENCES "Unit"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseTerms" ADD CONSTRAINT "LeaseTerms_leaseId_fkey" FOREIGN KEY ("leaseId") REFERENCES "Lease"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseParty" ADD CONSTRAINT "LeaseParty_leaseId_fkey" FOREIGN KEY ("leaseId") REFERENCES "Lease"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseDocument" ADD CONSTRAINT "LeaseDocument_leaseId_fkey" FOREIGN KEY ("leaseId") REFERENCES "Lease"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseRenewal" ADD CONSTRAINT "LeaseRenewal_leaseId_fkey" FOREIGN KEY ("leaseId") REFERENCES "Lease"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
